/* BTNavigationMenu — Figma 2065-2478 (Navigation Menu - Desktop).
   TabMenubar variants: node 2065-2424.
   All colours via @btech/tokens CSS vars — no hex fallbacks.
   Shared between Vue and React implementations. */

/* ── Root ─────────────────────────────────────────────────────────── */

.bt-nav-menu {
  display: flex;
  align-items: center;
  width: 100%;
  background: var(--bg-primary);
  padding: var(--space-lg) var(--space-xl);
  gap: var(--space-3xl);
  box-sizing: border-box;
}

/* ── Logo ─────────────────────────────────────────────────────────── */

.bt-nav-menu__logo {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  max-width: 107px;
  height: 40px;
}

/* ── Center section — nav items (menu type) ─────────────────────── */

.bt-nav-menu__center {
  display: flex;
  align-items: center;
  flex: 1;
  gap: var(--space-lg);
  min-width: 0;
}

/* ── Trailing section — search + profile ─────────────────────────── */

.bt-nav-menu__trailing {
  display: flex;
  align-items: center;
  gap: var(--space-lg);
  flex-shrink: 0;
}

/* ── Tab-style combined section (BTTabs + search, right-aligned) ─── */

.bt-nav-menu__tabs-section {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  flex: 1;
  gap: var(--space-lg);
  min-width: 0;
}

/* ── Tab-style / segmented — tighter item gap ───────────────────── */

.bt-nav-menu__tabs-section--segmented {
  gap: var(--space-xs);
}

/* ── Search wrapper ─────────────────────────────────────────────── */

.bt-nav-menu__search {
  width: 200px;
  flex-shrink: 0;
}

/* ── Nav item — TabMenubar base (Text Only default) ─────────────── */

.bt-nav-menu-item {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0;
  padding: var(--space-sm);
  border-radius: var(--radius-rd);
  cursor: pointer;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  line-height: var(--typography-line-height-xs);
  font-weight: 500;
  color: var(--text-secondary);
  background: transparent;
  border: none;
  outline: none;
  white-space: nowrap;
  user-select: none;
  transition: background-color 0.15s ease, color 0.15s ease;
}

/* TabMenubar — Icon + Text (node 2957-2777 / 2065-2422) */
.bt-nav-menu-item--icon-text {
  gap: var(--space-xs);
  padding-block: var(--space-sm);
  padding-inline: var(--space-sm) var(--space-md);
}

/* TabMenubar — Icon Only (node 2065-2423 / 3082-6516) */
.bt-nav-menu-item--icon-only {
  padding: var(--space-xs);
  border-radius: var(--radius-xs);
}

/* Hover (inactive): subtle bg + text turns primary */
.bt-nav-menu-item:hover:not(.bt-nav-menu-item--disabled):not(.bt-nav-menu-item--active) {
  background: var(--bg-subtle);
  color: var(--color-brand-primary);
}

/* Active — Text Only (node 3082-6543): bold brand text, no fill */
.bt-nav-menu-item--active:not(.bt-nav-menu-item--icon-text) {
  color: var(--color-brand-primary);
  font-weight: 700;
}

/* Active — Icon + Text (node 2065-2422): filled primary pill */
.bt-nav-menu-item--icon-text.bt-nav-menu-item--active {
  background: var(--color-brand-primary);
  color: var(--text-inverse);
  font-weight: 700;
}

.bt-nav-menu-item--icon-text.bt-nav-menu-item--active:hover:not(.bt-nav-menu-item--disabled) {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
}

.bt-nav-menu-item:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

.bt-nav-menu-item--disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Inline icons inside nav items ─────────────────────────────── */

.bt-nav-menu-item--icon-text > svg {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.bt-nav-menu-item--icon-only > svg {
  width: 24px;
  height: 24px;
  flex-shrink: 0;
}

/* ── Profile ──────────────────────────────────────────────────────── */

.bt-nav-menu__profile {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  width: 140px;
  flex-shrink: 0;
  cursor: pointer;
  border-radius: var(--radius-sm);
  padding: var(--space-xs) var(--space-sm);
  background: transparent;
  border: none;
  outline: none;
  text-align: start;
  transition: background-color 0.15s ease;
}

.bt-nav-menu__profile:hover {
  background: var(--bg-subtle);
}

.bt-nav-menu__profile:hover .bt-nav-menu__profile-chevron {
  color: var(--color-brand-primary);
}

.bt-nav-menu__profile:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

.bt-nav-menu__profile-text {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  gap: var(--space-2xs);
}

.bt-nav-menu__profile-name {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-nav-menu__profile-desc {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-nav-menu__profile-chevron {
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
  flex-shrink: 0;
}

/**
 * BTNavigationMenu public API types.
 *
 * Figma: node 2065-2478 (Navigation Menu - Desktop).
 * Web only — no Flutter implementation.
 */
import type { BTAvatarItem } from '../avatar/BTAvatar.types';
import type { BTTabItem, BTTabsVariant } from '../tabs/BTTabs.types';

export type BTNavigationMenuType = 'menu' | 'tab-style';

/** TabMenubar visual shape — maps to Figma .TabMenubar variants (node 2065-2424). */
export type BTNavigationMenuItemShape = 'text-only' | 'icon-text' | 'icon-only';

/** A single nav item in the menu bar. */
export interface BTNavigationMenuItem {
  /** Unique identifier for this item. */
  id: string;
  /** Label text displayed in the nav item. Omit for icon-only items. */
  label?: string;
  /** Whether this item is non-interactive. @default false */
  disabled?: boolean;
  /**
   * Renders as TabMenubar "Icon Only" (24×24 icon, 4 px padding, radius-xs).
   * Requires [startIcon]. When omitted, inferred when label is empty.
   */
  iconOnly?: boolean;
  /**
   * SVG path `d` attribute for an optional leading icon (24×24 viewBox).
   * Icon + Text: 16×16 before label. Icon Only: 24×24 standalone.
   */
  startIcon?: string;
}

/** Resolve TabMenubar shape from item props (Figma .TabMenubar node 2065-2424). */
export function getNavMenuItemShape(
  item: Pick<BTNavigationMenuItem, 'startIcon' | 'label' | 'iconOnly'>,
): BTNavigationMenuItemShape {
  const isIconOnly = Boolean(item.iconOnly || (item.startIcon && !item.label));
  if (isIconOnly) return 'icon-only';
  if (item.startIcon && item.label) return 'icon-text';
  return 'text-only';
}

/** Build BEM class list for a TabMenubar nav button. */
export function getNavMenuItemClassName(
  item: Pick<BTNavigationMenuItem, 'startIcon' | 'label' | 'iconOnly' | 'disabled'>,
  active: boolean,
): string {
  const shape = getNavMenuItemShape(item);
  return [
    'bt-nav-menu-item',
    active ? 'bt-nav-menu-item--active' : '',
    item.disabled ? 'bt-nav-menu-item--disabled' : '',
    shape === 'icon-only' ? 'bt-nav-menu-item--icon-only' : '',
    shape === 'icon-text' ? 'bt-nav-menu-item--icon-text' : '',
  ].filter(Boolean).join(' ');
}

/** Profile section data — shown at the trailing end of menu-type nav. */
export interface BTNavigationMenuProfile {
  /** Avatar payload — renders as BTAvatar size="sm". */
  avatar: BTAvatarItem;
  /** Primary name line (14 px bold). */
  name: string;
  /** Secondary description line (12 px, e.g. role or email). */
  description?: string;
}

export interface BTNavigationMenuProps {
  /**
   * Visual layout variant.
   * - `'menu'`       — logo | nav items + optional slot | search + profile
   * - `'tab-style'`  — logo | BTTabs line + optional search (right-aligned)
   * @default 'menu'
   */
  type?: BTNavigationMenuType;

  // ── menu type ─────────────────────────────────────────────────────

  /**
   * Navigation items for the `menu` variant.
   * Each renders as a pill item — optional leading icon via `startIcon`.
   */
  items?: BTNavigationMenuItem[];

  /**
   * ID of the currently active nav item (`menu` variant).
   * Controlled via `v-model:activeId`.
   */
  activeId?: string;

  /** Profile section shown at the trailing end (`menu` variant). */
  profile?: BTNavigationMenuProfile;

  // ── tab-style type ─────────────────────────────────────────────────

  /**
   * Tab items for the `tab-style` variant.
   * Passed directly to `BTTabs`.
   * Inlined here (not via BTTabItem import) so Vue's SFC compiler can declare
   * this as a runtime prop — the compiler doesn't follow cross-file import chains.
   */
  tabs?: Array<{ label: string; disabled?: boolean; startIcon?: string }>;

  /**
   * BTTabs variant for the `tab-style` layout.
   * - `'line'`      — underline indicator (default, matches Figma)
   * - `'segmented'` — filled pill buttons (TabMenubar style)
   * Inlined here so Vue's SFC compiler can declare this as a runtime prop.
   * @default 'line'
   */
  tabVariant?: 'line' | 'segmented';

  /**
   * Active tab index for the `tab-style` variant.
   * Controlled via `v-model:activeTabIndex`.
   */
  activeTabIndex?: number;

  // ── shared ─────────────────────────────────────────────────────────

  /**
   * When provided, shows a `BTInputSearch` in the trailing section.
   * Pass `''` to show the field with no pre-filled value.
   */
  searchValue?: string;
}

export type { BTAvatarItem, BTTabItem, BTTabsVariant };

export { default as BTNavigationMenu } from './BTNavigationMenu.vue';
export type {
  BTNavigationMenuProps,
  BTNavigationMenuType,
  BTNavigationMenuItem,
  BTNavigationMenuItemShape,
  BTNavigationMenuProfile,
} from './BTNavigationMenu.types';
export { getNavMenuItemClassName, getNavMenuItemShape } from './BTNavigationMenu.types';
